// Script: generar_88_esterilizado.js
// Que hace: cambia "Castrado/a" por "Esterilizado/a" y "Entero" por
// "Entero/a" en todos los lugares donde aparecia, y el label del
// formulario de nueva mascota de "¿Está castrado/a?" a
// "¿Está esterilizado/a?". El campo en la base de datos (castrado)
// no cambia — solo el texto visible en la app.
//
//   1) app/vet/page.tsx
//   2) components/DashboardContenido.tsx
//   3) app/mascota/nueva/page.tsx

const fs = require('fs'); const path = require('path');
function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}
escribir('app/vet/page.tsx', "");
escribir('components/DashboardContenido.tsx', "");
escribir('app/mascota/nueva/page.tsx', "");
